import{_ as r,o as t,c as o,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"EGO共鸣：振翅","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/EGO共鸣：振翅.md","filePath":"4.资源分区/6.技艺及称号/武技类/EGO共鸣：振翅.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/EGO共鸣：振翅.md"};function p(_,a,l,i,c,b){return t(),o("div",null,[...a[0]||(a[0]=[e("h1",{id:"ego共鸣-振翅",tabindex:"-1"},[n("EGO共鸣：振翅 "),e("a",{class:"header-anchor",href:"#ego共鸣-振翅","aria-label":'Permalink to "EGO共鸣：振翅"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),s('<h1 id="ego共鸣-振翅-1" tabindex="-1">EGO共鸣：振翅 <a class="header-anchor" href="#ego共鸣-振翅-1" aria-label="Permalink to &quot;EGO共鸣：振翅&quot;">​</a></h1><p>EGO共鸣：振翅<br> D+1000</p><p>他的内脏和眼球遭到不明生物啃食，受损严重。此外，我们察觉到精灵们的嘴角沾有某人的血肉。</p><p>以一个整轮动作启用，你选定一名可怜的受害者，对其进行一次冲锋攻击，本次攻击的伤害类型转为挥砍伤害，并且这次冲锋攻击中你的基础防御不会降低，在你第一次斩击切下其血肉之后，你恢复1点完好或韧性，这是一个【快速医疗1（医疗点12）】效果。随后，你调转方向，对其进行重复的斩击，重复攻击的次数为投掷4次rd2，若出目为1则视作成功重复攻击一次，每次重复攻击仅会造成额外的1点多次攻击减值而不视作一次完整的攻击，本次攻击的实际伤害会平分至首次攻击和每次重复攻击之中。（如轮回者A投掷出4个1，那么本次攻击造成5点多次攻击减值，本次攻击造成实际伤害为10点，那么则变为受到2点伤害5次）</p><p>——解析II：额外支付D+1000，开启贪食被动：<br> 当你使用振翅后，在本场景内，当你对某位敌人造成实际伤害时，若这不是其第一次受到的实际伤害，那么每造成3点实际伤害，则为你恢复1点完好值或韧性值，每回合最多恢复3点，这是一个【吸血3】效果。<br> ——解析III：额外支付C+1500，<br> 现在在你使用振翅时，你每成功进行一次重复攻击，那么你本次攻击的实际伤害倍率提升0.4，但是你本次攻击的基础伤害倍率降低至0.4倍。（即当你成功重复攻击的次数达到1/2/3/4时，实际伤害倍率提升至0.8/1.2/1.6/2.0倍）<br> 并且你每成功进行一次重复攻击，那么你获得1点仅在本次攻击中生效的吸血。<br> ——解析IV：额外支付B+2000，<br> 在解析III中获得的效果改为：你每成功进行一次重复攻击，那么你本次攻击的实际伤害倍率提升0.6，但是你本次攻击的基础伤害倍率降低至0.6倍。（即当你成功重复攻击的次数达到1/2/3/4时，实际伤害倍率提升至1.2/1.8/2.4/3.0倍）<br> 并且你每成功进行一次重复攻击，那么你获得2点仅在本次攻击中生效的吸血。<br> 此时振翅会附带等量的流血异常点数</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const E=r(d,[["render",p]]);export{f as __pageData,E as default};
